"use client";

import { useSession, signOut } from "next-auth/react";
import { useState } from "react";
import styles from "./dashboard.module.css";
import NeuralNetworkBackground from "@/components/NeuralNetworkBackground";

// Mock Repos (Replace with actual data fetching)
const repositories = [
  "AmanM006/Appointment-AI-Slack",
  "AmanM006/GitHelix-Core",
  "AmanM006/Portfolio-v3"
];

export default function Dashboard() {
  const { data: session } = useSession();
  const [selectedRepo, setSelectedRepo] = useState(repositories[0]);
  const [isScanning, setIsScanning] = useState(false);

  const handleScan = () => {
    setIsScanning(true);
    // Add scanning logic here
    setTimeout(() => setIsScanning(false), 2000);
  };

  return (
    <div className={styles.container}>
      
      {/* 1. Background Layer */}
      <div style={{position: 'fixed', inset: 0, pointerEvents: 'none'}}>
        <NeuralNetworkBackground />
      </div>

      {/* 2. The Main Console Card */}
      <div className={styles.consoleCard}>
        
        {/* Header */}
        <header className={styles.header}>
          <div className={styles.logo}>GitHelix Dashboard</div>
          
          <div className={styles.userInfo}>
            {session?.user?.name && (
              <span className={styles.userName}>
                Signed in as {session.user.name}
              </span>
            )}
            <button 
              onClick={() => signOut({ callbackUrl: "/" })}
              className={styles.signOutBtn}
            >
              Sign Out
            </button>
          </div>
        </header>

        {/* Content Body */}
        <main className={styles.content}>
          <div className={styles.bgGrid}></div>

          {/* Scan Controls */}
          <div className={styles.scanSection}>
            <label className={styles.label}>Select Target Repository</label>
            
            <div className={styles.controlsRow}>
              <select 
                value={selectedRepo}
                onChange={(e) => setSelectedRepo(e.target.value)}
                className={styles.repoSelect}
              >
                {repositories.map(repo => (
                  <option key={repo} value={repo}>{repo}</option>
                ))}
              </select>

              <button 
                onClick={handleScan}
                className={styles.startScanBtn}
                disabled={isScanning}
              >
                {isScanning ? "Scanning..." : "Start Scan"}
              </button>
            </div>

            <div className={styles.statusText}>
              {isScanning 
                ? "Engine Active: Analyzing vector embeddings..." 
                : "System Ready. Select a repository to begin analysis."
              }
            </div>
          </div>

        </main>
      </div>
    </div>
  );
}